@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    """
    Downloads an invoice PDF file given its ID.

    Assumes authentication middleware has already verified the user
    and that the user is authorized to download this specific invoice.
    """
    invoice_filename = f"{invoice_id}.pdf"
    
    # Ensure the invoice ID is positive and potentially within a valid range
    # (though `int` conversion already handles basic type checking, a real app
    # might check against a database of valid invoice IDs for the user)
    if invoice_id <= 0:
        abort(400, description="Invalid invoice ID.")

    try:
        # Use send_from_directory to securely serve files
        # It handles path traversal protection.
        return send_from_directory(
            directory=INVOICE_STORAGE_DIRECTORY,
            path=invoice_filename,
            as_attachment=True,  # Suggests browser to download rather than display
            mimetype='application/pdf'
        )
    except FileNotFoundError:
        # If the file doesn't exist, return a 404 error.
        abort(404, description=f"Invoice with ID {invoice_id} not found.")
    except Exception as e:
        # Catch any other unexpected errors during file serving
        app.logger.error(f"Error serving invoice {invoice_id}: {e}")
        abort(500, description="An error occurred while trying to download the invoice.")

